  console.log('Source unavailable — returning empty records');
  return [{ json: { kaggle_records: [], kaggle_count: 0, error: 'Source unavailable' } }];
}

const FASHION_SIGNALS = {
  'post-mastectomy': 'post-surgical bras, front-closure tops, prosthesis-compatible swimwear',
  'alopecia': 'head scarves, adaptive headwear, wig alternatives, sun protection hats',
  'diabetes': 'insulin pump clothing, CGM-compatible waistbands, non-restrictive footwear',
  'adaptive-mobility': 'wheelchair-adapted cuts, magnetic closures, seated-fit trousers',
  'cancer-recovery': 'soft-touch fabrics, port-access tops, compression-friendly layers'
};

const items = $input.all();
const records = [];

for (const item of items.slice(0, 100)) {
  const row = item.json;

  if (!row['Age'] || row['Age'] === 'Age') continue;
  const age = parseInt(row['Age']);
  if (isNaN(age) || age < 1 || age > 120) continue;
  if (!row['Level']) continue;

  const level = row['Level'].toLowerCase().trim();
  const fatigue = parseFloat(row['Fatigue'] || 0);
  const weightLoss = parseFloat(row['Weight Loss'] || 0);
  const obesity = parseFloat(row['Obesity'] || 0);
  const smoking = parseFloat(row['Smoking'] || 0);

  let category = 'cancer-recovery';
  if (level === 'high') {
    category = (weightLoss > 4 || fatigue > 4) ? 'cancer-recovery' : 'post-mastectomy';
  } else if (level === 'medium') {
    if (obesity > 4) category = 'diabetes';
    else if (smoking > 5) category = 'adaptive-mobility';
    else category = 'cancer-recovery';
  } else if (level === 'low') {
    category = 'alopecia';
  }

  const treatmentStage = level === 'high' ? 'active-treatment' : level === 'medium' ? 'monitoring' : 'post-treatment';
  const genderVal = row['Gender'] === '1' ? 'Male' : row['Gender'] === '2' ? 'Female' : null;

  records.push({
    record_id: 'kag_' + Math.random().toString(36).substr(2, 9),
    source: 'kaggle',
    category: category,
    age: age,
    gender: genderVal,
    condition: `cancer — severity: ${row['Level']}`,
    treatment_stage: treatmentStage,
    fashion_signal: FASHION_SIGNALS[category],
    date_collected: '2026-05-28',
    notes: `Smoking:${row['Smoking']||'?'} Obesity:${row['Obesity']||'?'} Fatigue:${row['Fatigue']||'?'} WeightLoss:${row['Weight Loss']||'?'}`
  });
}

return [{ json: { kaggle_records: records, kaggle_count: records.length } }];

