// Node: Parse HuggingFace Clinical Notes
// Dataset: AGBonnet/augmented-clinical-notes
// Fields: note, full_note, conversation, summary

const FASHION_SIGNALS = {
  'post-mastectomy': 'post-surgical bras, front-closure tops, prosthesis-compatible swimwear',
  'alopecia': 'head scarves, adaptive headwear, wig alternatives, sun protection hats',
  'diabetes': 'insulin pump clothing, CGM-compatible waistbands, non-restrictive footwear',
  'adaptive-mobility': 'wheelchair-adapted cuts, magnetic closures, seated-fit trousers',
  'cancer-recovery': 'soft-touch fabrics, port-access tops, compression-friendly layers'
};

const CATEGORY_KEYWORDS = {
  'post-mastectomy': ['mastectomy', 'breast cancer', 'lumpectomy', 'breast mass', 'breast tumor', 'mammogram'],
  'alopecia': ['alopecia', 'hair loss', 'chemotherapy', 'hair thinning', 'scalp'],
  'diabetes': ['diabetes', 'diabetic', 'insulin', 'glucose', 'hyperglycemia', 'type 2', 'type 1'],
  'adaptive-mobility': ['wheelchair', 'mobility', 'prosthetic', 'arthritis', 'amputation', 'rheumatoid', 'orthopedic'],
  'cancer-recovery': ['cancer', 'oncology', 'chemotherapy', 'radiation', 'tumor', 'carcinoma', 'survivorship', 'malignant']
};

const inputItem = $input.first();
const data = inputItem.json;
const rows = data.rows || [];

const records = [];

for (const rowObj of rows.slice(0, 80)) {
  const row = rowObj.row || rowObj;
  const text = (row.note || row.full_note || row.summary || row.conversation || '').toLowerCase();

  if (!text || text.length < 20) continue;

  // Match category
  let matchedCategory = null;
  for (const [cat, keywords] of Object.entries(CATEGORY_KEYWORDS)) {
    if (keywords.some(kw => text.includes(kw))) {
      matchedCategory = cat;
      break;
    }
  }
  if (!matchedCategory) continue;

  // Infer treatment stage from clinical language
  let treatmentStage = 'active-treatment';
  if (text.includes('follow-up') || text.includes('post-op') || text.includes('recovery') || text.includes('discharged') || text.includes('remission')) {
    treatmentStage = 'post-treatment';
  } else if (text.includes('newly diagnosed') || text.includes('new onset') || text.includes('presenting with') || text.includes('initial diagnosis')) {
    treatmentStage = 'newly-diagnosed';
  } else if (text.includes('monitoring') || text.includes('surveillance') || text.includes('stable')) {
    treatmentStage = 'monitoring';
  }

  // Extract condition name from text
  const conditionMap = {
    'post-mastectomy': 'breast cancer / post-mastectomy',
    'alopecia': 'alopecia / chemotherapy-induced hair loss',
    'diabetes': 'diabetes mellitus',
    'adaptive-mobility': 'mobility impairment / adaptive needs',
    'cancer-recovery': 'cancer / oncology recovery'
  };

  const noteText = (row.note || row.summary || '').replace(/\n/g, ' ').trim();

  records.push({
    record_id: 'hf_' + Math.random().toString(36).substr(2, 9),
    source: 'huggingface',
    category: matchedCategory,
    age: null,
    gender: null,
    condition: conditionMap[matchedCategory],
    treatment_stage: treatmentStage,
    fashion_signal: FASHION_SIGNALS[matchedCategory],
    date_collected: '2026-05-28',
    notes: noteText.substring(0, 200)
  });

  if (records.length >= 50) break;
}

return [{ json: { hf_records: records, hf_count: records.length } }];

