  `<div style="background:${CATEGORY_COLORS[cat]}15;border-left:4px solid ${CATEGORY_COLORS[cat]};padding:16px;border-radius:8px;"><div style="font-size:28px;font-weight:800;color:${CATEGORY_COLORS[cat]}">${count}</div><div style="font-size:13px;color:#333;margin-top:4px">${CATEGORY_LABELS[cat] || cat}</div></div>`
